import time
import sys
import random

# ANSI Escape Codes for colors and styles
CLR = {
    "RESET": "\033[0m",
    "BOLD": "\033[1m",
    "ITALIC": "\033[3m",
    "RED": "\033[91m",
    "CYAN": "\033[96m",
    "YELLOW": "\033[93m",
    "MAGENTA": "\033[95m",
    "BLUE": "\033[94m",
    "GREEN": "\033[92m",
    "WHITE": "\033[97m",
    "GRAY": "\033[90m"
}

def clear_screen():
    print("\033[H\033[J", end="")

def typewriter(text, delay=0.06, color=CLR["WHITE"]):
    """Prints text with a typing effect."""
    for char in text:
        sys.stdout.write(f"{color}{char}\033[0m")
        sys.stdout.flush()
        time.sleep(delay)
    print()

def draw_frame(quote, author):
    """Draws a neurotic, shaky-looking frame around the quote."""
    width = 60
    print(CLR["GRAY"] + "┌" + "─" * (width - 2) + "┐" + CLR["RESET"])
    
    # Handle multi-line text for the box
    lines = [quote[i:i+width-4] for i in range(0, len(quote), width-4)]
    
    for line in lines:
        padding = " " * ((width - 2 - len(line)) // 2)
        right_padding = " " * (width - 2 - len(line) - len(padding))
        print(f"│{CLR['GRAY']}{padding}{CLR['WHITE']}{line}{CLR['GRAY']}{right_padding}│")
        
    print(f"└{'─' * (width - 2)}┘" + CLR["RESET"])
    print(f"{''* (width//2 - len(author)//2)}{CLR['ITALIC']}{author}{CLR['RESET']}\n")

def neurosis_animation():
    """An animation representing existential dread/anxiety."""
    frames = [
        "   (o _ o)   ",
        "   ( >_< )   ",
        "   ( @ _ @ ) ",
        "   ( T _ T ) ",
        "   ( - _ - ) "
    ]
    for _ in range(3):
        for frame in frames:
            sys.stdout.write(f"\r{CLR['RED']}{frame}{CLR['RESET']}")
            sys.stdout.flush()
            time.sleep(0.15)

def main():
    clear_screen()
    
    # The Woody Allen style quote
    quote = ("\"I find it impossible to focus on the meaning of life when "
             "the meaning of life is constantly interrupted by my own "
             "sudden, inexplicable fear of being perceived by strangers.\"")
    author = "-- A Neurotic Philosopher"

    # Intro sequence
    print(f"\n{CLR['GRAY']}Initializing Existential Dread...{CLR['RESET']}\n")
    time.sleep(1)
    
    # Neurotic visual
    for _ in range(2):
        neurosis_animation()
        time.sleep(0.3)
    print("\n")

    # The main event
    print(f"{CLR['CYAN']}--- A Moment of Uncomfortable Reflection ---{CLR['RESET']}\n")
    time.sleep(1)
    
    # Draw the box and type the quote
    # Since we want typewriter effect inside a frame, we'll simulate it 
    # by printing the frame first, then the content.
    
    print(f"{CLR['GRAY']}┌" + "─" * 58 + "┐")
    print(f"│{CLR['GRAY']}                                                            {CLR['RESET']}│")
    
    # We split the quote to fit the box
    words = quote.split()
    current_line = ""
    lines = []
    for word in words:
        if len(current_line + word) < 54:
            current_line += word + " "
        else:
            lines.append(current_line.strip())
            current_line = word + " "
    lines.append(current_line.strip())

    # Printing the quote with animation
    for line in lines:
        padding = " " * ((58 - len(line)) // 2)
        print(f"│{CLR['GRAY']}  {CLR['RESET']}", end="")
        
        # Typewriter effect for the line
        for char in padding + line + " " * (58 - len(padding) - len(line)):
            sys.stdout.write(f"{CLR['WHITE']}{char}{CLR['RESET']}")
            sys.stdout.flush()
            time.sleep(0.02)
        
        print(f"{CLR['GRAY']}  │{CLR['RESET']}")
    
    print(f"│{CLR['GRAY']}                                                            │")
    print(f"└{'─' * 58}┘{CLR['RESET']}")
    
    time.sleep(0.5)
    print(f"\n{CLR['YELLOW']}{author}{CLR['RESET']}\n")
    
    # Final-ish touch
    print(f"{CLR['GRAY']}(Please wait for the inevitable void...){CLR['RESET']}")
    time.sleep(2)
    print(f"{CLR['RED']}VOID DETECTED.{CLR['RESET']}\n")

